import type { DataRow, FilterState, ProductConfig } from '../types';

/**
 * Hàm core áp dụng bộ lọc trạng thái xuất vào tập dữ liệu
 */
export function filterByExportStatus(data: DataRow[], filterValue: string): DataRow[] {
  if (filterValue === 'all') return data;

  return data.filter(row => {
    // Tìm cột trạng thái xuất (hỗ trợ nhiều tên cột khác nhau nếu có)
    const rawValue = (row['Trạng thái xuất'] || row['Trạng thái xuất kho'] || '').toString().toLowerCase();

    // Logic chuẩn hóa:
    const isShipped = rawValue.includes('đã');
    const isPending = rawValue.includes('chưa') || rawValue.includes('chờ');

    if (filterValue === 'Đã') return isShipped;
    if (filterValue === 'Chưa') return isPending;

    return true;
  });
}

// Giả sử đây là hàm tổng hợp chính
export function applyAllFilters(data: DataRow[], filters: FilterState): DataRow[] {
    let result = [...data];

    // Lọc theo kho...

    // Lọc theo trạng thái xuất
    result = filterByExportStatus(result, filters.xuat);

    // Lọc theo ngày tháng...

    return result;
}

import type { DataRow, FilterState } from '../types';

export function applyAllFilters(allData: DataRow[], filters: FilterState): DataRow[] {
  if (!allData || allData.length === 0) return [];

  return allData.filter(row => {
    // 1. Lọc theo Kho
    if (filters.kho !== 'all' && row['Mã kho tạo'] !== filters.kho) return false;

    // 2. Lọc theo Trạng thái xuất
    if (filters.xuat !== 'all') {
      const rawXuat = (row['Trạng thái xuất'] || '').toString().toLowerCase();
      const isShipped = rawXuat.includes('đã');
      if (filters.xuat === 'Đã' && !isShipped) return false;
      if (filters.xuat === 'Chưa' && isShipped) return false;
    }

    // 3. Lọc theo Khoảng ngày
    if (filters.startDate || filters.endDate) {
      const rowDate = row.parsedDate; // Giả sử đã được parse ở bước upload
      if (!rowDate) return false;

      if (filters.startDate) {
        const start = new Date(filters.startDate);
        start.setHours(0, 0, 0, 0);
        if (rowDate < start) return false;
      }

      if (filters.endDate) {
        const end = new Date(filters.endDate);
        end.setHours(23, 59, 59, 999);
        if (rowDate > end) return false;
      }
    }

    // 4. Các bộ lọc nâng cao khác (Người tạo, Bộ phận...)
    if (filters.nguoiTao.length > 0 && !filters.nguoiTao.includes(row['Người tạo'])) return false;

    return true;
  });
}

/**
 * Định dạng tiền tệ: 1.500.000 -> 1.5 Tr, 1.500.000.000 -> 1.5 Tỷ
 */
export function formatCurrency(num: number): string {
  if (!num || isNaN(num)) return '0';

  if (Math.abs(num) >= 1_000_000_000) {
    return (num / 1_000_000_000).toFixed(2).replace(/\.00$/, '') + ' Tỷ';
  }
  if (Math.abs(num) >= 1_000_000) {
    return (num / 1_000_000).toFixed(1).replace(/\.0$/, '') + ' Tr';
  }
  if (Math.abs(num) >= 1_000) {
    return (num / 1_000).toFixed(0) + ' K';
  }
  return num.toLocaleString('vi-VN');
}

/**
 * Định dạng số lượng đơn hàng
 */
export function formatNumber(num: number): string {
  if (!num || isNaN(num)) return '0';
  return num.toLocaleString('vi-VN');
}

import * as XLSX from 'xlsx';

self.onmessage = async (e) => {
  const { file, config } = e.data;

  try {
    const data = await file.arrayBuffer();
    const workbook = XLSX.read(data, { type: 'array', cellDates: true });
    const sheetName = workbook.SheetNames[0];
    const rawJson = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName], { defval: '' });

    // Logic Lọc dữ liệu sạch
    const cleanedData = rawJson.filter(row => {
      const isNotCanceled = (row['Trạng thái hủy'] || '').toString().toLowerCase().includes('chưa');
      const isNotReturned = (row['Tình trạng nhập trả của sản phẩm đổi với sản phẩm chính'] || '').toString().toLowerCase().includes('chưa');
      const isPaid = (row['Trạng thái thu tiền'] || '').toString().toLowerCase().includes('đã');
      return isNotCanceled && isNotReturned && isPaid;
    });

    self.postMessage({ type: 'SUCCESS', payload: cleanedData });
  } catch (error) {
    self.postMessage({ type: 'ERROR', message: error.message });
  }
};

import type { ProductConfig } from '../types';

const CONFIG_URL = 'https://docs.google.com/spreadsheets/d/e/YOUR_LINK_HERE/pub?output=csv';

export async function fetchProductConfig(): Promise<Record<string, number>> {
  try {
    const response = await fetch(CONFIG_URL);
    const csvText = await response.text();

    // Parse CSV đơn giản
    const lines = csvText.split('\n').slice(1); // Bỏ dòng header
    const configMap: Record<string, number> = {};

    lines.forEach(line => {
      const [nhomCha, nhomCon, maNhomHang, heSo] = line.split(',');
      if (maNhomHang && heSo) {
        configMap[maNhomHang.trim()] = parseFloat(heSo);
      }
    });

    return configMap;
  } catch (error) {
    console.error('Không thể tải file cấu hình hệ số:', error);
    // Trả về mặc định nếu lỗi
    return {};
  }
}

import { get } from 'svelte/store';
import { productConfig } from '../stores/dashboardStore';

/**
 * Lấy hệ số quy đổi dựa trên mã nhóm hàng
 * Ưu tiên: Tra cứu trong file cấu hình -> Fallback theo tên ngành hàng -> Mặc định 1.0
 */
export function getConversionFactor(maNhomHang: string, nganhHangText: string): number {
  const config = get(productConfig);

  // 1. Kiểm tra trong map cấu hình (Ưu tiên cao nhất)
  if (config && config[maNhomHang]) {
    return config[maNhomHang];
  }

  // 2. Fallback logic dựa trên tên ngành hàng (Nếu file cấu hình thiếu)
  const name = nganhHangText.toLowerCase();
  if (name.includes('phụ kiện')) return 3.37;
  if (name.includes('gia dụng')) return 1.85;
  if (name.includes('bảo hiểm')) return 4.18;
  if (name.includes('sim')) return 5.45;
  if (name.includes('đồng hồ')) return 3.0;

  // 3. Mặc định là 1.0 (Smartphone, Laptop, Tablet, Tivi...)
  return 1.0;
}

/**
 * Tính toán DTQĐ cho một dòng dữ liệu
 */
export function calculateRowQD(row: any) {
  const price = parseFloat(row['Giá bán_1']) || 0;
  const maNhomHang = (row['Nhóm hàng'] || '').toString();
  const nganhHang = (row['Ngành hàng'] || '').toString();

  const factor = getConversionFactor(maNhomHang, nganhHang);

  return {
    revenue: price,
    revenueQD: price * factor,
    factor: factor
  };
}

import { calculateRowQD } from '../utils/calculationUtils';
import type { DataRow, KpiData } from '../types';

export function processRawData(rows: DataRow[]): { filtered: DataRow[], kpis: KpiData } {
  let totalThuc = 0;
  let totalQD = 0;
  let countThuHo = 0;

  const processed = rows.map(row => {
    // Tích hợp tính toán quy đổi vào từng dòng
    const { revenue, revenueQD, factor } = calculateRowQD(row);

    // Tích lũy tổng
    totalThuc += revenue;
    totalQD += revenueQD;

    if ((row['Hình thức xuất'] || '').includes('thu hộ')) {
      countThuHo++;
    }

    return {
      ...row,
      computedRevenue: revenue,
      computedRevenueQD: revenueQD,
      appliedFactor: factor
    };
  });

  const kpis: KpiData = {
    totalRevenue: totalThuc,
    doanhThuQD: totalQD,
    hieuQuaQD: totalThuc > 0 ? (totalQD - totalThuc) / totalThuc : 0,
    soLuongThuHo: countThuHo,
    // ... các chỉ số khác
  };

  return { filtered: processed, kpis };
}

