import { get } from 'svelte/store';
import { productConfig } from '../stores/dashboardStore';

/**
 * Lấy hệ số quy đổi
 * Logic mới: Kiểm tra tên sản phẩm Vieon trước khi tra cứu mã nhóm
 */
export function getConversionFactor(maNhomHang: string, nganhHangText: string, productName: string): number {
  const name = (productName || '').toString();

  // 1. Logic đặc thù cho sản phẩm Vieon (Ưu tiên cao nhất)
  if (name.includes('VieON VIP')) {
    if (name.includes('01 tháng')) return 1;
    if (name.includes('03 tháng')) return 2;
    if (name.includes('06 tháng')) return 4;
    // Các gói Vieon khác nếu có
    return 1; 
  }

  const config = get(productConfig);

  // 2. Kiểm tra trong map cấu hình (Admin update)
  if (config && config[maNhomHang]) {
    return config[maNhomHang];
  }

  // 3. Fallback logic dựa trên tên ngành hàng
  const nganhLow = nganhHangText.toLowerCase();
  if (nganhLow.includes('phụ kiện')) return 3.37;
  if (nganhLow.includes('gia dụng')) return 1.85;
  if (nganhLow.includes('bảo hiểm')) return 4.18;
  if (nganhLow.includes('sim')) return 5.45;
  if (nganhLow.includes('đồng hồ')) return 3.0;

  return 1.0;
}

/**
 * Tính toán DTQĐ cho một dòng dữ liệu
 */
export function calculateRowQD(row: any) {
  const price = parseFloat(row['Giá bán_1']) || 0;
  const maNhomHang = (row['Nhóm hàng'] || '').toString();
  const nganhHang = (row['Ngành hàng'] || '').toString();

  // Lấy tên sản phẩm từ row dựa trên các bí danh đã định nghĩa
  const productName = row['Tên sản phẩm'] || row['Tên Sản Phẩm'] || '';

  const factor = getConversionFactor(maNhomHang, nganhHang, productName);

  return {
    revenue: price,
    revenueQD: price * factor,
    factor: factor
  };
}

