export function getRowValue(row: DataRow, keys: string[]): any {
    for (const key of keys) {
        if (row[key] !== undefined && row[key] !== null) return row[key];
    }
    return undefined;
}

export function toLocalISOString(date: Date | null): string {
    if (!date) return '';
    const year = date.getFullYear();
    const month = (date.getMonth() + 1).toString().padStart(2, '0');
    const day = date.getDate().toString().padStart(2, '0');
    return `${year}-${month}-${day}`;
}

export function parseExcelDate(excelDate: any): Date | null {
    if (excelDate instanceof Date && !isNaN(excelDate.getTime())) return excelDate;
    if (typeof excelDate === 'number') {
        return new Date(Math.round((excelDate - 25569) * 86400 * 1000));
    }
    if (typeof excelDate === 'string') {
        const date = new Date(excelDate);
        if (!isNaN(date.getTime())) return date;
    }
    return null;
}

export function abbreviateName(fullName: string): string {
    if (!fullName || !fullName.includes(' - ')) return fullName;
    const parts = fullName.split(' - ');
    const id = parts[0];
    const name = parts[1];
    const nameWords = name.trim().split(' ');
    if (nameWords.length <= 1) return fullName;
    const lastName = nameWords[nameWords.length - 1];
    const middleNameInitial = nameWords.length > 2 ? nameWords[nameWords.length - 2].charAt(0).toUpperCase() : nameWords[0].charAt(0).toUpperCase();
    return `${id} - ${middleNameInitial}.${lastName}`;
}

export function formatCurrency(number: number, precision = 0): string {
    if (isNaN(number) || number === 0) return '-';
    if (Math.abs(number) >= 1000000000) return `${(number / 1000000000).toFixed(1).replace(/\.0$/, '')} Tỷ`;
    if (Math.abs(number) >= 1000000) return `${(number / 1000000).toFixed(precision).replace(/\.0$/, '')} Tr`;
    if (Math.abs(number) >= 1000) return `${Math.round(number / 1000)} K`;
    return number.toLocaleString('vi-VN');
}

export function formatRevenueForHeadToHead(value: number | undefined): string {
    if (value === undefined || isNaN(value) || value === 0) return '-';
    const roundedValue = Math.round(value / 1000000);
    return roundedValue.toLocaleString('vi-VN');
}

export function formatQuantity(value: number | null | undefined): string {
    if (value == null || isNaN(value) || value === 0) return '-';
    return value.toLocaleString('vi-VN');
}

export function formatQuantityWithFraction(value: number | null | undefined): string {
    if (value == null || isNaN(value) || value === 0) return '-';
    return value.toLocaleString('vi-VN', { maximumFractionDigits: 1 });
}


export function getHeSoQuyDoi(maNganhHang: string, maNhomHang: string, productConfig: ProductConfig | null, productName?: string): number {
    // 0. Logic đặc thù cho Vieon dựa trên tên sản phẩm (Ưu tiên cao nhất)
    const name = (productName || '').toString();
    if (name.includes('VieON VIP')) {
        if (name.includes('01 tháng')) return 1;
        if (name.includes('03 tháng')) return 2;
        if (name.includes('06 tháng')) return 4;
        return 1;
    }

    const parentGroup = productConfig?.childToParentMap?.[maNhomHang];

    // Priority 1: Use parent group from config file for primary categories
    if (parentGroup) {
        switch (parentGroup) {
            case 'Phụ kiện': return 3.37;
            case 'Wearable': 
            case 'Đồng hồ': return 3.0;
            case 'Laptop': return 1.2;
            case 'Tablet': return 1.2;
            case 'Gia dụng': return 1.85;
            case 'Sim': return 5.45;
            case 'Bảo hiểm': return 4.18;
            case 'IT': return 2.0;
            case 'Thẻ cào':
            case 'ICT': // Smartphones are in here
            case 'CE': // Tivi, etc.
                return 1.0;
            default:
                break;
        }
    }

    // Priority 2: Fallback to old logic for compatibility or items not in config
    if (maNganhHang && maNganhHang.includes('Thẻ cào')) return 1.0;
    if (maNganhHang === '164 - VAS' && (maNhomHang === '4479 - Dịch Vụ Bảo Hiểm' || maNhomHang === '4499 - Thu Hộ Phí Bảo Hiểm')) return 4.18;
    if (maNganhHang === '304 - Điện tử' && maNhomHang === '880 - Loa Karaoke') return 1.29;

    switch (maNganhHang) {
        case '664 - Sim Online': return 5.45;
        case '16 - Phụ kiện tiện ích':
        case '184 - Phụ kiện trang trí':
        case '764 - Loa vi tính': return 3.37;
        case '23 - Wearable':
        case '1274 - Đồng Hồ Thời Trang': return 3.0;
        case '364 - IT': return 2.0;
        case '1034 - Dụng cụ nhà bếp': return 1.92;
        case '1116 - Máy lọc nước':
        case '484 - Điện gia dụng':
        case '1214 - Gia dụng lắp đặt': return 1.85;
        case '22 - Laptop':
        case '244 - Tablet': return 1.2;
        default: return 1.0;
    }
}

export function sortSummaryData(data: { [key: string]: SummaryTableNode }, sortKey: string, sortDir: 'asc' | 'desc'): { [key: string]: SummaryTableNode } {
    const sortFn = (a: [string, SummaryTableNode], b: [string, SummaryTableNode]) => {
        const nodeA = a[1];
        const nodeB = b[1];
        let valA, valB;

        switch(sortKey) {
           case 'aov':
                valA = nodeA.totalQuantity > 0 ? nodeA.totalRevenue / nodeA.totalQuantity : 0;
                valB = nodeB.totalQuantity > 0 ? nodeB.totalRevenue / nodeB.totalQuantity : 0;
                break;
           case 'traGopPercent':
                valA = nodeA.totalRevenue > 0 ? (nodeA.totalTraGop / nodeA.totalRevenue) * 100 : 0;
                valB = nodeB.totalRevenue > 0 ? (nodeB.totalTraGop / nodeB.totalRevenue) * 100 : 0;
                break;
           default:
                valA = nodeA[sortKey as keyof SummaryTableNode] || 0;
                valB = nodeB[sortKey as keyof SummaryTableNode] || 0;
        }

        if (valA === valB) return 0;
        const result = (valA < valB) ? -1 : 1;
        return sortDir === 'asc' ? result : -result;
    };

    const sortedEntries = Object.entries(data).sort(sortFn);
    const sortedData = Object.fromEntries(sortedEntries);

    for (const key in sortedData) {
        if (Object.keys(sortedData[key].children).length > 0) {
            sortedData[key].children = sortSummaryData(sortedData[key].children, sortKey, sortDir);
        }
    }
    return sortedData;
}

export function isValidSale(row: DataRow): boolean {
    const getString = (keys: string[]) => (getRowValue(row, keys) || '').toString().trim().toLowerCase();

    return getString(COL.TRANG_THAI_HUY) === 'chưa hủy' &&
           getString(COL.TINH_TRANG_NHAP_TRA) === 'chưa trả' &&
           getString(COL.TRANG_THAI_THU_TIEN) === 'đã thu';
}

export function getHinhThucThanhToan(row: DataRow): 'tra_gop' | 'tien_mat' | 'thu_ho' | 'khac' {
    const hinhThucXuat = getRowValue(row, COL.HINH_THUC_XUAT);
    if (HINH_THUC_XUAT_TRA_GOP.has(hinhThucXuat)) return 'tra_gop';
    if (HINH_THUC_XUAT_TIEN_MAT.has(hinhThucXuat)) return 'tien_mat';
    if (HINH_THUC_XUAT_THU_HO.has(hinhThucXuat)) return 'thu_ho';
    return 'khac';
}

export const getDisplayParentGroup = (maNhomHang: string, productConfig: ProductConfig): string => {
    const parentGroup = productConfig.childToParentMap[maNhomHang] || 'Khác';
    const childGroup = productConfig.childToSubgroupMap[maNhomHang];

    if (parentGroup === 'ICT' && ['Smartphone', 'Laptop', 'Tablet'].includes(childGroup)) {
        return childGroup;
    }
    if (parentGroup === 'Gia dụng' && childGroup === 'Máy lọc nước') {
        return 'Máy lọc nước';
    }
    return parentGroup;
};

import { useMemo } from 'react';
import type { DataRow, ProductConfig, Employee, HeadToHeadTableConfig } from '../types';
import { getRowValue, toLocalISOString, getHeSoQuyDoi } from '../utils/dataUtils';
import { COL, HINH_THUC_XUAT_THU_HO } from '../constants';

interface UseHeadToHeadLogicProps {
    config: HeadToHeadTableConfig;
    baseFilteredData: DataRow[];
    productConfig: ProductConfig;
    employeeData: Employee[];
    sortConfig: { key: string | number; direction: 'asc' | 'desc' };
    includeToday: boolean;
}

export const useHeadToHeadLogic = ({
    config,
    baseFilteredData,
    productConfig,
    employeeData,
    sortConfig,
    includeToday
}: UseHeadToHeadLogicProps) => {
    return useMemo(() => {
        const employeeDepartments = new Map(employeeData.map(e => [e.name, e.department]));
        const baseDate = new Date();
        baseDate.setHours(0, 0, 0, 0);
        if (!includeToday) baseDate.setDate(baseDate.getDate() - 1);

        const dateHeaders = Array.from({ length: 7 }).map((_, i) => { const d = new Date(baseDate); d.setDate(d.getDate() - i); return d; }).reverse();
        const startDate = dateHeaders[0];
        const endDate = new Date(baseDate);
        endDate.setHours(23, 59, 59, 999);
        const dateRangeString = `${startDate.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit' })} - ${endDate.toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit' })}`;

        const isValidSale = (row: DataRow): boolean => 
            (getRowValue(row, COL.TRANG_THAI_HUY) || '').toString().trim().toLowerCase() === 'chưa hủy' && 
            (getRowValue(row, COL.TINH_TRANG_NHAP_TRA) || '').toString().trim().toLowerCase() === 'chưa trả' && 
            (getRowValue(row, COL.TRANG_THAI_THU_TIEN) || '').toString().trim().toLowerCase() === 'đã thu';

        const dataForTab = baseFilteredData.filter(row => !HINH_THUC_XUAT_THU_HO.has(getRowValue(row, COL.HINH_THUC_XUAT)) && isValidSale(row));

        const groupFilteredData = (config.selectedSubgroups.length === 0 && (!config.selectedParentGroups || config.selectedParentGroups.length === 0))
            ? dataForTab
            : dataForTab.filter(row => {
                const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
                const parentGroup = productConfig.childToParentMap[maNhomHang];
                const subgroup = productConfig.childToSubgroupMap[maNhomHang];

                const parentMatch = config.selectedParentGroups && parentGroup && config.selectedParentGroups.includes(parentGroup);
                const subgroupMatch = config.selectedSubgroups && subgroup && config.selectedSubgroups.includes(subgroup);

                return !!(parentMatch || subgroupMatch);
            });

        const salesByEmployeeByDate: { [emp: string]: { [dateKey: string]: { revenue: number, revenueQD: number, quantity: number } } } = {};

        groupFilteredData.forEach(row => {
            const date = row.parsedDate;
            if (!date || date < startDate || date > endDate) return;

            const employee = getRowValue(row, COL.NGUOI_TAO);
            const dateKey = toLocalISOString(date);
            if (!employee) return;

            if (!salesByEmployeeByDate[employee]) salesByEmployeeByDate[employee] = {};
            if (!salesByEmployeeByDate[employee][dateKey]) salesByEmployeeByDate[employee][dateKey] = { revenue: 0, revenueQD: 0, quantity: 0 };

            const price = Number(getRowValue(row, COL.PRICE)) || 0;
            const quantity = Number(getRowValue(row, COL.QUANTITY)) || 0;
            const revenue = price; 
            const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
            const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
            const productName = getRowValue(row, COL.PRODUCT);

            const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
            const revenueQD = revenue * heso;

            // Logic: Với Vieon, nhân Số lượng với hệ số quy đổi
            const subgroup = productConfig.childToSubgroupMap[maNhomHang];
            const parentGroup = productConfig.childToParentMap[maNhomHang];
            const isVieon = subgroup === 'Vieon' || parentGroup === 'Vieon' || (productName || '').toString().includes('VieON');

            const weightedQuantity = isVieon ? (quantity * heso) : quantity;

            salesByEmployeeByDate[employee][dateKey].revenue += revenue;
            salesByEmployeeByDate[employee][dateKey].revenueQD += revenueQD;
            salesByEmployeeByDate[employee][dateKey].quantity += weightedQuantity;
        });

        // Pre-calculate daily totals for all employees for HQQD calculation
        const dailyGrandTotals = new Map<string, { revenue: number, revenueQD: number }>();
        if (config.metricType === 'hieuQuaQD') {
            dateHeaders.forEach(date => {
                const dateKey = toLocalISOString(date);
                dailyGrandTotals.set(dateKey, { revenue: 0, revenueQD: 0 });
            });

            Object.values(salesByEmployeeByDate).forEach(empSales => {
                Object.entries(empSales).forEach(([dateKey, dailyMetrics]) => {
                    const dayTotal = dailyGrandTotals.get(dateKey);
                    if (dayTotal) {
                        dayTotal.revenue += dailyMetrics.revenue;
                        dayTotal.revenueQD += dailyMetrics.revenueQD;
                    }
                });
            });
        }


        let tableRows = employeeData.map(emp => {
            const empSales = salesByEmployeeByDate[emp.name] || {};
            let total = 0;
            let daysWithSales = 0;
            const dailyValues: { [dateKey: string]: number } = {};

            let totalRevenue7Days = 0;
            let totalRevenueQD7Days = 0;

            dateHeaders.forEach(date => {
                const dateKey = toLocalISOString(date);
                const dailyMetrics = empSales[dateKey] || { revenue: 0, revenueQD: 0, quantity: 0 };

                totalRevenue7Days += dailyMetrics.revenue;
                totalRevenueQD7Days += dailyMetrics.revenueQD;

                let value = 0;
                switch(config.metricType) {
                    case 'quantity': value = dailyMetrics.quantity; break;
                    case 'revenue': value = dailyMetrics.revenue; break;
                    case 'revenueQD': value = dailyMetrics.revenueQD; break;
                    case 'hieuQuaQD':
                        value = dailyMetrics.revenue > 0 ? ((dailyMetrics.revenueQD / dailyMetrics.revenue) - 1) * 100 : 0;
                        break;
                }

                dailyValues[dateKey] = value;
                if (value > 0) daysWithSales++;
                if (config.metricType !== 'hieuQuaQD') {
                    total += value;
                }
            });

            if (config.metricType === 'hieuQuaQD') {
                total = totalRevenue7Days > 0 ? ((totalRevenueQD7Days / totalRevenue7Days) - 1) * 100 : 0;
            }

            if (config.totalCalculationMethod === 'average' && config.metricType !== 'hieuQuaQD') {
                total /= 7;
            }

            const rowValues = Object.values(dailyValues);
            const rowAverage = rowValues.reduce((a, b) => a + b, 0) / (rowValues.filter(v => v > 0).length || 1);

            return { 
                name: emp.name, 
                department: employeeDepartments.get(emp.name) || 'Không Phân Ca',
                dailyValues, 
                total, 
                daysWithNoSales: 7 - daysWithSales,
                rowAverage
            };
        });

        // --- START: BOTTOM 30% CALCULATION ---
        const rowsByDept: { [key: string]: typeof tableRows } = {};
        tableRows.forEach(row => {
            const dept = row.department;
            if (!rowsByDept[dept]) rowsByDept[dept] = [];
            rowsByDept[dept].push(row);
        });

        const bottom30PercentNames = new Set<string>();
        Object.values(rowsByDept).forEach(deptRows => {
            if (deptRows.length > 3) { // Only apply if there's a meaningful number of employees
                const sortedByTotal = [...deptRows].sort((a, b) => a.total - b.total); // Sort ascending
                const thresholdIndex = Math.floor(deptRows.length * 0.3);
                const thresholdValue = sortedByTotal[thresholdIndex].total;

                // Add all employees at or below the threshold, including ties
                sortedByTotal.forEach(row => {
                    if (row.total <= thresholdValue && row.total > 0) { // only highlight if they sold something
                        bottom30PercentNames.add(row.name);
                    }
                });
            }
        });

        tableRows.forEach(row => {
            (row as any).isBottom30 = bottom30PercentNames.has(row.name);
        });

        const top30PercentNoSalesNames = new Set<string>();
        const rowsWithActivity = tableRows.filter(r => r.daysWithNoSales < 7);
        if (rowsWithActivity.length > 3) {
            const sortedByNoSales = [...rowsWithActivity].sort((a,b) => b.daysWithNoSales - a.daysWithNoSales);
            const thresholdIndex = Math.floor(sortedByNoSales.length * 0.3);
            if (thresholdIndex < sortedByNoSales.length) {
                const thresholdValue = sortedByNoSales[thresholdIndex].daysWithNoSales;
                sortedByNoSales.forEach(r => {
                    if (r.daysWithNoSales >= thresholdValue && r.daysWithNoSales > 0) {
                        top30PercentNoSalesNames.add(r.name);
                    }
                });
            }
        }

        const deptAvgByDate = new Map<string, Map<string, number>>();
        dateHeaders.forEach(date => {
            const dateKey = toLocalISOString(date);
            const dailyDeptStats = new Map<string, { sum: number, count: number }>();
            tableRows.forEach(row => {
                const dept = row.department;
                const value = row.dailyValues[dateKey] || 0;
                if (!dailyDeptStats.has(dept)) dailyDeptStats.set(dept, { sum: 0, count: 0 });
                const stats = dailyDeptStats.get(dept)!;
                stats.sum += value;
                stats.count++;
            });
            const avgMap = new Map<string, number>();
            dailyDeptStats.forEach((stats, dept) => {
                avgMap.set(dept, stats.count > 0 ? stats.sum / stats.count : 0);
            });
            deptAvgByDate.set(dateKey, avgMap);
        });

        tableRows.sort((a, b) => {
            const valA = a[sortConfig.key as keyof typeof a];
            const valB = b[sortConfig.key as keyof typeof b];

            if (typeof valA === 'number' && typeof valB === 'number') {
                if (valA !== valB) return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
            }
            return b.total - a.total; 
        });

        const groupedRows: { [key: string]: typeof tableRows } = tableRows.reduce((acc, row) => {
            const dept = row.department;
            if (!acc[dept]) acc[dept] = [];
            acc[dept].push(row);
            return acc;
        }, {} as { [key: string]: typeof tableRows });

        const sortedDepartments = Object.keys(groupedRows).sort((a,b) => a.localeCompare(b));

        const departmentTotals = new Map<string, any>();
        sortedDepartments.forEach(dept => {
            const rowsInDept = groupedRows[dept];
            const deptTotals = { daily: new Map<string, number>(), total: 0, daysWithNoSales: 0 };

            if (rowsInDept.length > 0) {
                dateHeaders.forEach(date => {
                    const dateKey = toLocalISOString(date);
                    if (config.metricType === 'hieuQuaQD') {
                        let dailyDeptRevenue = 0;
                        let dailyDeptRevenueQD = 0;
                        rowsInDept.forEach(row => {
                            const dailyMetrics = salesByEmployeeByDate[row.name]?.[dateKey];
                            if (dailyMetrics) {
                                dailyDeptRevenue += dailyMetrics.revenue;
                                dailyDeptRevenueQD += dailyMetrics.revenueQD;
                            }
                        });
                        const dailyDeptHqqd = dailyDeptRevenue > 0 ? ((dailyDeptRevenueQD / dailyDeptRevenue) - 1) * 100 : 0;
                        deptTotals.daily.set(dateKey, dailyDeptHqqd);
                    } else {
                        const dailyDeptTotal = rowsInDept.reduce((sum, row) => sum + (row.dailyValues[dateKey] || 0), 0);
                        deptTotals.daily.set(dateKey, dailyDeptTotal);
                    }
                });

                if (config.metricType === 'hieuQuaQD') {
                    const deptTotalRevenue = rowsInDept.reduce((sum, r) => sum + Object.values(salesByEmployeeByDate[r.name] || {}).reduce((s, d) => s + d.revenue, 0), 0);
                    const deptTotalRevenueQD = rowsInDept.reduce((sum, r) => sum + Object.values(salesByEmployeeByDate[r.name] || {}).reduce((s, d) => s + d.revenueQD, 0), 0);
                    const totalHqqd = deptTotalRevenue > 0 ? ((deptTotalRevenueQD / deptTotalRevenue) - 1) * 100 : 0;

                    if (config.totalCalculationMethod === 'average') {
                        deptTotals.total = rowsInDept.reduce((sum, r) => sum + r.total, 0) / (rowsInDept.length || 1);
                    } else {
                        deptTotals.total = totalHqqd;
                    }
                } else {
                    deptTotals.total = rowsInDept.reduce((sum, r) => sum + r.total, 0);
                    if (config.totalCalculationMethod === 'average') {
                        deptTotals.total /= (rowsInDept.length || 1);
                    }
                }
                deptTotals.daysWithNoSales = rowsInDept.reduce((sum, r) => sum + r.daysWithNoSales, 0) / (rowsInDept.length || 1);
            }
            departmentTotals.set(dept, deptTotals);
        });

        const totals = { daily: new Map<string, number>(), total: 0, daysWithNoSales: 0 };
        let grandTotalRevenue = 0;
        let grandTotalRevenueQD = 0;

        if (tableRows.length > 0) {
            tableRows.forEach(row => {
                dateHeaders.forEach(date => { const dateKey = toLocalISOString(date); const value = row.dailyValues[dateKey] || 0; totals.daily.set(dateKey, (totals.daily.get(dateKey) || 0) + value); });
                if (config.metricType !== 'hieuQuaQD') { totals.total += row.total; }
                totals.daysWithNoSales += row.daysWithNoSales;
            });
            totals.daysWithNoSales /= tableRows.length;
        }

        if (config.metricType === 'hieuQuaQD') {
             dateHeaders.forEach(date => {
                const dateKey = toLocalISOString(date);
                const dayTotal = dailyGrandTotals.get(dateKey);
                if (dayTotal && dayTotal.revenue > 0) {
                    totals.daily.set(dateKey, ((dayTotal.revenueQD / dayTotal.revenue) - 1) * 100);
                } else {
                    totals.daily.set(dateKey, 0);
                }
            });

             Object.values(salesByEmployeeByDate).forEach(empSales => { Object.values(empSales).forEach(dailyMetrics => { grandTotalRevenue += dailyMetrics.revenue; grandTotalRevenueQD += dailyMetrics.revenueQD; }); });
            const totalHqqd = grandTotalRevenue > 0 ? ((grandTotalRevenueQD / grandTotalRevenue) - 1) * 100 : 0;
             if (config.totalCalculationMethod === 'average') { totals.total = tableRows.reduce((sum, r) => sum + r.total, 0) / (tableRows.length || 1);
            } else { totals.total = totalHqqd; }
        } else if (config.totalCalculationMethod === 'average') { totals.total = tableRows.reduce((sum, r) => sum + r.total, 0) / (tableRows.length || 1); }

        return { 
            processedData: { tableRows, dateHeaders, dateRangeString, totals, top30PercentNoSalesNames, groupedRows, sortedDepartments },
            conditionalFormatData: { deptAvgByDate },
            departmentTotals
        };
    }, [config, baseFilteredData, productConfig, employeeData, includeToday, sortConfig]);
};

import type { DataRow, KpiData, ProductConfig } from '../types';
import { COL, HINH_THUC_XUAT_THU_HO } from '../constants';
import { getRowValue, getHeSoQuyDoi, getHinhThucThanhToan } from '../utils/dataUtils';

/**
 * Calculates key performance indicators from various data sources.
 */
export function processKpis(
    validSalesData: DataRow[],
    unshippedOrders: DataRow[],
    allPeriodData: DataRow[],
    productConfig: ProductConfig | null
): KpiData {
    let doanhThuQD = 0;
    let totalRevenue = 0;
    let traGopValue = 0;
    let traGopCount = 0;

    validSalesData.forEach(row => {
        const price = Number(getRowValue(row, COL.PRICE)) || 0;
        const rowRevenue = price; // Doanh thu là giá trị của cột Giá bán_1
        const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
        const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
        const productName = getRowValue(row, COL.PRODUCT);

        const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);

        totalRevenue += rowRevenue;
        doanhThuQD += rowRevenue * heso;

        if (getHinhThucThanhToan(row) === 'tra_gop') {
            traGopValue += rowRevenue;
            traGopCount++;
        }
    });

    const { doanhThuThucChoXuat, doanhThuQDChoXuat } = unshippedOrders.reduce((acc, row) => {
        const price = Number(getRowValue(row, COL.PRICE)) || 0;
        const rowRevenue = price; // Doanh thu là giá trị của cột Giá bán_1
        const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
        const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
        const productName = getRowValue(row, COL.PRODUCT);

        const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
        acc.doanhThuThucChoXuat += rowRevenue;
        acc.doanhThuQDChoXuat += rowRevenue * heso;
        return acc;
    }, { doanhThuThucChoXuat: 0, doanhThuQDChoXuat: 0 });

    const soLuongThuHo = allPeriodData.filter(row => HINH_THUC_XUAT_THU_HO.has(getRowValue(row, COL.HINH_THUC_XUAT))).length;

    return {
        doanhThuQD,
        totalRevenue,
        soLuongThuHo,
        hieuQuaQD: totalRevenue > 0 ? (doanhThuQD - totalRevenue) / totalRevenue : 0,
        traGopPercent: totalRevenue > 0 ? (traGopValue / totalRevenue) * 100 : 0,
        traGopValue,
        traGopCount,
        doanhThuThucChoXuat,
        doanhThuQDChoXuat,
    };
}

import type { DataRow, TrendData, ProductConfig } from '../types';
import { COL } from '../constants';
import { getRowValue, getHeSoQuyDoi } from '../utils/dataUtils';

export function processTrendData(
    salesData: DataRow[],
    productConfig: ProductConfig | null
): TrendData {
    const daily: { [key: string]: { revenue: number, revenueQD: number, date: Date } } = {};
    const shifts: { [key: string]: { revenue: number, revenueQD: number } } = { "Ca 1": { revenue: 0, revenueQD: 0 }, "Ca 2": { revenue: 0, revenueQD: 0 }, "Ca 3": { revenue: 0, revenueQD: 0 }, "Ca 4": { revenue: 0, revenueQD: 0 }, "Ca 5": { revenue: 0, revenueQD: 0 }, "Ca 6": { revenue: 0, revenueQD: 0 } };

    salesData.forEach(row => {
        const price = Number(getRowValue(row, COL.PRICE)) || 0;
        const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
        const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
        const productName = getRowValue(row, COL.PRODUCT);

        const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
        const revenue = price; // Doanh thu là giá trị của cột Giá bán_1
        const revenueQD = revenue * heso;

        const dateCreated: Date = row.parsedDate;
        if (dateCreated && !isNaN(dateCreated.getTime())) {
             const dayKey = dateCreated.toISOString().split('T')[0];
            if (!daily[dayKey]) daily[dayKey] = { revenue: 0, revenueQD: 0, date: dateCreated };
            daily[dayKey].revenue += revenue;
            daily[dayKey].revenueQD += revenueQD;

            const hour = dateCreated.getHours();
            const minute = dateCreated.getMinutes();

            let ca: string | null = null;

            if (hour === 8) { // Ca 1: 8:00 - 8:59
                ca = "Ca 1";
            } else if (hour >= 9 && hour < 12) { // Ca 2: 9:00 - 11:59
                ca = "Ca 2";
            } else if (hour >= 12 && hour < 15) { // Ca 3: 12:00 - 14:59
                ca = "Ca 3";
            } else if (hour >= 15 && hour < 18) { // Ca 4: 15:00 - 17:59
                ca = "Ca 4";
            } else if (hour >= 18 && hour < 21) { // Ca 5: 18:00 - 20:59
                ca = "Ca 5";
            } else if (hour === 21 && minute < 30) { // Ca 6: 21:00 - 21:29
                ca = "Ca 6";
            }

            if (ca && shifts[ca]) {
                shifts[ca].revenue += revenue;
                shifts[ca].revenueQD += revenueQD;
            }
        }
    });

    return { daily, shifts };
}

import type { DataRow, ProductConfig, Employee, EmployeeData, ExploitationData } from '../types';
import { COL, HINH_THUC_XUAT_THU_HO } from '../constants';
import { getRowValue, getHeSoQuyDoi, getDisplayParentGroup, getHinhThucThanhToan } from '../utils/dataUtils';
import { DepartmentMap } from './dataService';

function _buildFullEmployeeData(
    employeeStats: { [key: string]: Partial<Employee> & { name: string, customerSet: Set<string>, totalOrders: number, doanhThuTraCham: number, slCE_ICT: number, slTraCham_CE_ICT: number, doanhThu_CE_ICT: number, doanhThuTraCham_CE_ICT: number } },
    exploitationStats: { [creator: string]: Partial<ExploitationData> & { name: string } },
    periodData: DataRow[],
    employeeIndustryStats: { [creator: string]: { [industry: string]: number } },
    employeeDailyTrend: { [creator: string]: { [date: string]: number } },
    departmentMap: DepartmentMap | null
): EmployeeData {

    const allCreatorsInPeriod = new Set(periodData.map(r => getRowValue(r, COL.NGUOI_TAO)).filter(Boolean));

    allCreatorsInPeriod.forEach(creator => {
        const creatorThuHoCount = periodData.filter(r => getRowValue(r, COL.NGUOI_TAO) === creator && HINH_THUC_XUAT_THU_HO.has(getRowValue(r, COL.HINH_THUC_XUAT))).length;

        if (employeeStats[creator]) {
             employeeStats[creator].slThuHo = (employeeStats[creator].slThuHo || 0) + creatorThuHoCount;
        } else if (creatorThuHoCount > 0) {
             employeeStats[creator] = { name: creator, doanhThuThuc: 0, doanhThuQD: 0, slTraCham: 0, doanhThuTraCham: 0, slThuHo: creatorThuHoCount, customerSet: new Set(), totalOrders: 0, slCE_ICT: 0, slTraCham_CE_ICT: 0, doanhThu_CE_ICT: 0, doanhThuTraCham_CE_ICT: 0 };
        }

        if (exploitationStats[creator] === undefined && employeeStats[creator] !== undefined) {
             exploitationStats[creator] = { name: creator };
        }

        if (departmentMap && (employeeStats[creator] || exploitationStats[creator])) {
            const creatorId = creator.split(' - ')[0].trim();
            const dept = departmentMap[creatorId];
            if (dept) {
                if (employeeStats[creator]) employeeStats[creator].department = dept;
                if (exploitationStats[creator]) exploitationStats[creator].department = dept;
            }
        }
    });

    let finalEmployeeStats = employeeStats;
    let finalExploitationStats = exploitationStats;
    let finalIndustryStats = employeeIndustryStats;
    let finalDailyTrend = employeeDailyTrend;

    if (departmentMap && Object.keys(departmentMap).length > 0) {
        const employeeIdsInMap = new Set(Object.keys(departmentMap));
        const filterPredicate = ([creator, _]: [string, any]) => {
            const creatorId = creator.split(' - ')[0].trim();
            return employeeIdsInMap.has(creatorId);
        };

        finalEmployeeStats = Object.fromEntries(Object.entries(employeeStats).filter(filterPredicate));
        finalExploitationStats = Object.fromEntries(Object.entries(exploitationStats).filter(filterPredicate));
        finalIndustryStats = Object.fromEntries(Object.entries(employeeIndustryStats).filter(filterPredicate));
        finalDailyTrend = Object.fromEntries(Object.entries(employeeDailyTrend).filter(filterPredicate));
    }

    const fullSellerArray: Employee[] = Object.values(finalEmployeeStats).map(emp => {
        const doanhThuThuc = emp.doanhThuThuc || 0;
        const doanhThuQD = emp.doanhThuQD || 0;
        const slTraCham = emp.slTraCham || 0;
        const doanhThuTraCham = emp.doanhThuTraCham || 0;
        const slTiepCan = emp.customerSet.size;
        const totalOrders = emp.totalOrders || 0;
        const slCE_ICT = emp.slCE_ICT || 0;
        const slTraCham_CE_ICT = emp.slTraCham_CE_ICT || 0;
        const doanhThu_CE_ICT = emp.doanhThu_CE_ICT || 0;
        const doanhThuTraCham_CE_ICT = emp.doanhThuTraCham_CE_ICT || 0;

        return {
            name: emp.name,
            department: emp.department || 'Không Phân Ca',
            doanhThuThuc,
            doanhThuQD,
            doanhThuTraCham,
            hieuQuaValue: doanhThuThuc > 0 ? ((doanhThuQD - doanhThuThuc) / doanhThuThuc) * 100 : 0,
            slTiepCan,
            aov: slTiepCan > 0 ? doanhThuThuc / slTiepCan : 0,
            slThuHo: emp.slThuHo || 0,
            slTraCham,
            totalOrders: totalOrders,
            traChamPercent: doanhThuThuc > 0 ? (doanhThuTraCham / doanhThuThuc) * 100 : 0,
            slCE_ICT,
            slTraCham_CE_ICT,
            traChamPercent_CE_ICT: slCE_ICT > 0 ? (slTraCham_CE_ICT / slCE_ICT) * 100 : 0,
            doanhThu_CE_ICT,
            doanhThuTraCham_CE_ICT,
            dtTraChamPercent_CE_ICT: doanhThu_CE_ICT > 0 ? (doanhThuTraCham_CE_ICT / doanhThu_CE_ICT) * 100 : 0,
            weakPointsRevenue: 0,
            weakPointsExploitation: 0,
        };
    });

    const exploitationData: ExploitationData[] = Object.values(finalExploitationStats)
        .filter(ex => ex.name)
        .map(ex => {
            const doanhThuThuc = ex.doanhThuThuc || 0;
            const doanhThuQD = ex.doanhThuQD || 0;
            const slBaoHiem = ex.slBaoHiem || 0;
            const slSPChinh_Tong = (ex.slICT || 0) + (ex.slCE_main || 0) + (ex.slGiaDung_main || 0);
            return {
                name: ex.name!,
                department: ex.department || 'Không Phân Ca',
                doanhThuThuc,
                doanhThuQD,
                hieuQuaQD: doanhThuThuc > 0 ? (doanhThuQD - doanhThuThuc) / doanhThuThuc * 100 : 0,

                slICT: ex.slICT || 0,
                doanhThuICT: ex.doanhThuICT || 0,
                slCE_main: ex.slCE_main || 0,
                doanhThuCE_main: ex.doanhThuCE_main || 0,
                slGiaDung_main: ex.slGiaDung_main || 0,

                slBaoHiem,
                doanhThuBaoHiem: ex.doanhThuBaoHiem || 0,
                percentBaoHiem: slSPChinh_Tong > 0 ? (slBaoHiem / slSPChinh_Tong) * 100 : 0,
                slSim: ex.slSim || 0,
                doanhThuSim: ex.doanhThuSim || 0,
                slDongHo: ex.slDongHo || 0,
                doanhThuDongHo: ex.doanhThuDongHo || 0,
                doanhThuPhuKien: ex.doanhThuPhuKien || 0,
                slPhuKien: ex.slPhuKien || 0,
                slCamera: ex.slCamera || 0,
                slLoa: ex.slLoa || 0,
                slPinSDP: ex.slPinSDP || 0,
                slTaiNgheBLT: ex.slTaiNgheBLT || 0,
                doanhThuGiaDung: ex.doanhThuGiaDung || 0,
                slGiaDung: ex.slGiaDung || 0,
                slMayLocNuoc: ex.slMayLocNuoc || 0,
                slNoiCom: ex.slNoiCom || 0,
                slNoiChien: ex.slNoiChien || 0,
                slQuatDien: ex.slQuatDien || 0,
            };
    });

    const sellersWithSales = fullSellerArray.filter(s => s.doanhThuThuc > 0);
    const totalSellersWithSales = sellersWithSales.length;

    return {
        fullSellerArray,
        exploitationData,
        byIndustry: finalIndustryStats,
        dailyTrend: finalDailyTrend,
        averages: {
            doanhThuThuc: sellersWithSales.reduce((sum, s) => sum + s.doanhThuThuc, 0) / (totalSellersWithSales || 1),
            doanhThuQD: sellersWithSales.reduce((sum, s) => sum + s.doanhThuQD, 0) / (totalSellersWithSales || 1),
            hieuQuaValue: sellersWithSales.reduce((sum, s) => sum + s.hieuQuaValue, 0) / (totalSellersWithSales || 1),
        },
        maxValues: {
            doanhThuThuc: Math.max(0, ...sellersWithSales.map(s => s.doanhThuThuc)),
            doanhThuQD: Math.max(0, ...sellersWithSales.map(s => s.doanhThuQD)),
        },
    };
}


export function processEmployeeData(
    salesData: DataRow[],
    periodData: DataRow[],
    productConfig: ProductConfig,
    departmentMap: DepartmentMap | null
): EmployeeData {

    const employeeStats: { [creator: string]: Partial<Employee> & { name: string, customerSet: Set<string>, totalOrders: number, doanhThuTraCham: number, slCE_ICT: number, slTraCham_CE_ICT: number, doanhThu_CE_ICT: number, doanhThuTraCham_CE_ICT: number } } = {};
    const exploitationStats: { [creator: string]: Partial<ExploitationData> & { name: string } } = {};
    const employeeIndustryStats: { [creator: string]: { [industry: string]: number } } = {};
    const employeeDailyTrend: { [creator: string]: { [date: string]: number } } = {};

    salesData.forEach(row => {
        const creator = getRowValue(row, COL.NGUOI_TAO);
        if (!creator) return;

        const price = Number(getRowValue(row, COL.PRICE)) || 0;
        const quantity = Number(getRowValue(row, COL.QUANTITY)) || 0;
        const revenue = price; // Doanh thu là giá trị của cột Giá bán_1
        const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
        const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
        const productName = getRowValue(row, COL.PRODUCT);

        const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
        const revenueQD = revenue * heso;
        const customer = getRowValue(row, COL.CUSTOMER_NAME);
        const dateCreated: Date = row.parsedDate;
        const dateKey = dateCreated.toISOString().split('T')[0];

        // --- Initialize stats objects ---
        if (!employeeStats[creator]) employeeStats[creator] = { name: creator, doanhThuThuc: 0, doanhThuQD: 0, slTraCham: 0, doanhThuTraCham: 0, customerSet: new Set(), totalOrders: 0, slCE_ICT: 0, slTraCham_CE_ICT: 0, doanhThu_CE_ICT: 0, doanhThuTraCham_CE_ICT: 0 };
        if (!exploitationStats[creator]) exploitationStats[creator] = { name: creator, slICT: 0, doanhThuICT: 0, slCE_main: 0, doanhThuCE_main: 0, slGiaDung_main: 0, slBaoHiem: 0, doanhThuBaoHiem: 0, slSim: 0, doanhThuSim: 0, slDongHo: 0, doanhThuDongHo: 0, doanhThuPhuKien: 0, slPhuKien: 0, slCamera: 0, slLoa: 0, slPinSDP: 0, slTaiNgheBLT: 0, doanhThuGiaDung: 0, slGiaDung: 0, slMayLocNuoc: 0, slNoiCom: 0, slNoiChien: 0, slQuatDien: 0 };
        if (!employeeIndustryStats[creator]) employeeIndustryStats[creator] = {};
        if (!employeeDailyTrend[creator]) employeeDailyTrend[creator] = {};
        if (!employeeDailyTrend[creator][dateKey]) employeeDailyTrend[creator][dateKey] = 0;

        // Logic trọng số cho Vieon khi tính số lượng
        const subgroup = productConfig.childToSubgroupMap[maNhomHang];
        const isVieon = subgroup === 'Vieon' || (productName || '').toString().includes('VieON');
        const weightedQuantity = isVieon ? (quantity * heso) : quantity;

        // --- Aggregate general stats ---
        const emp = employeeStats[creator];
        emp.doanhThuThuc! += revenue;
        emp.doanhThuQD! += revenueQD;
        emp.totalOrders! += 1;
        if (customer) emp.customerSet.add(customer);
        if (getHinhThucThanhToan(row) === 'tra_gop') {
            emp.slTraCham! += weightedQuantity; // Cập nhật số lượng trọng số
            emp.doanhThuTraCham! += revenue;
        }

        const parentGroupForPerf = productConfig.childToParentMap[maNhomHang] || 'Không xác định';
        if (parentGroupForPerf === 'CE' || parentGroupForPerf === 'ICT') {
            emp.slCE_ICT! += weightedQuantity; // Cập nhật số lượng trọng số
            emp.doanhThu_CE_ICT! += revenue;
            if (getHinhThucThanhToan(row) === 'tra_gop') {
                emp.slTraCham_CE_ICT! += weightedQuantity; // Cập nhật số lượng trọng số
                emp.doanhThuTraCham_CE_ICT! += revenue;
            }
        }

        // --- Aggregate industry stats ---
        const displayGroup = getDisplayParentGroup(maNhomHang, productConfig);
        employeeIndustryStats[creator][displayGroup] = (employeeIndustryStats[creator][displayGroup] || 0) + revenue;
        employeeDailyTrend[creator][dateKey] += revenueQD;

        // --- Aggregate exploitation stats ---
        const stats = exploitationStats[creator];
        stats.doanhThuThuc = (stats.doanhThuThuc || 0) + revenue;
        stats.doanhThuQD = (stats.doanhThuQD || 0) + revenueQD;

        const parentGroup = productConfig.childToParentMap[maNhomHang] || 'Không xác định';
        const childGroup = productConfig.childToSubgroupMap[maNhomHang] || 'Không xác định';

        // SP Chính
        if (parentGroup === 'ICT') {
            stats.slICT! += weightedQuantity;
            stats.doanhThuICT! += revenue;
        } else if (parentGroup === 'CE') {
            stats.slCE_main! += weightedQuantity;
            stats.doanhThuCE_main! += revenue;
        } else if (parentGroup === 'Gia dụng') {
            stats.slGiaDung_main! += weightedQuantity; 
        }

        // Bán Kèm & Các nhóm khác
        if (parentGroup === 'Bảo hiểm') {
            stats.slBaoHiem! += weightedQuantity;
            stats.doanhThuBaoHiem! += revenue;
        } else if (parentGroup === 'Sim') {
            stats.slSim! += weightedQuantity;
            stats.doanhThuSim! += revenue;
        } else if (parentGroup === 'Đồng hồ' || parentGroup === 'Wearable') { 
            stats.slDongHo! += weightedQuantity;
            stats.doanhThuDongHo! += revenue;
        } else if (parentGroup === 'Phụ kiện') {
            stats.doanhThuPhuKien! += revenue;
            stats.slPhuKien! += weightedQuantity; 
            if (childGroup === 'Camera') stats.slCamera! += weightedQuantity;
            else if (childGroup === 'Loa') stats.slLoa! += weightedQuantity;
            else if (childGroup === 'Pin SDP') stats.slPinSDP! += weightedQuantity;
            else if (childGroup === 'Tai nghe BLT') stats.slTaiNgheBLT! += weightedQuantity;
        } else if (parentGroup === 'Gia dụng') {
            stats.doanhThuGiaDung! += revenue;
            stats.slGiaDung! += weightedQuantity; 
            if (childGroup === 'Máy lọc nước') stats.slMayLocNuoc! += weightedQuantity;
            else if (childGroup === 'NC đ.tử/cao tần' || childGroup === 'NC nắp gài/rời') stats.slNoiCom! += weightedQuantity;
            else if (childGroup === 'Nồi chiên') stats.slNoiChien! += weightedQuantity;
            else if (childGroup === 'Quạt điện') stats.slQuatDien! += weightedQuantity;
        }
    });

    const initialEmployeeData = _buildFullEmployeeData(employeeStats, exploitationStats, periodData, employeeIndustryStats, employeeDailyTrend, departmentMap);

    // --- Calculate Weakness Points ---
    const employeesByDept: { [key: string]: Employee[] } = {};
    initialEmployeeData.fullSellerArray.forEach(emp => {
        if (!employeesByDept[emp.department]) {
            employeesByDept[emp.department] = [];
        }
        employeesByDept[emp.department].push(emp);
    });

    const deptThresholds: { [key: string]: any } = {};
    for (const dept in employeesByDept) {
        const deptEmployees = employeesByDept[dept];
        const count = deptEmployees.length;
        if (count > 0) {
            deptThresholds[dept] = {
                dtqd_40p: [...deptEmployees].sort((a, b) => a.doanhThuQD - b.doanhThuQD)[Math.floor(count * 0.4)]?.doanhThuQD,
                slCE_ICT_30p: [...deptEmployees].sort((a, b) => a.slCE_ICT - b.slCE_ICT)[Math.floor(count * 0.3)]?.slCE_ICT,
                slTraCham_CE_ICT_30p: [...deptEmployees].sort((a, b) => a.slTraCham_CE_ICT - b.slTraCham_CE_ICT)[Math.floor(count * 0.3)]?.slTraCham_CE_ICT,
            };
        }
    }

    const finalFullSellerArray = initialEmployeeData.fullSellerArray.map(emp => {
        const thresholds = deptThresholds[emp.department];
        let weakPointsRevenue = 0;
        let weakPointsExploitation = 0;

        if (thresholds) {
            if (emp.doanhThuQD <= thresholds.dtqd_40p) weakPointsRevenue++;
            if (emp.hieuQuaValue < 35) weakPointsRevenue++;
            if (emp.dtTraChamPercent_CE_ICT < 45) weakPointsRevenue++;

            if (emp.slCE_ICT <= thresholds.slCE_ICT_30p) weakPointsExploitation++;
            if (emp.slTraCham_CE_ICT <= thresholds.slTraCham_CE_ICT_30p) weakPointsExploitation++;
            if (emp.traChamPercent_CE_ICT < 50) weakPointsExploitation++;
        }

        return { ...emp, weakPointsRevenue, weakPointsExploitation };
    });

    return { ...initialEmployeeData, fullSellerArray: finalFullSellerArray };
}

import type { DataRow, ProductConfig, FilterState, SummaryTableNode, GrandTotal, WarehouseSummaryRow, MetricValues } from '../types';
import { COL, HINH_THUC_XUAT_THU_HO, HINH_THUC_XUAT_TRA_GOP } from '../constants';
import { getRowValue, getHeSoQuyDoi, sortSummaryData, getHinhThucThanhToan, getDisplayParentGroup, abbreviateName } from '../utils/dataUtils';

export function processSummaryTable(
    filteredValidSalesData: DataRow[],
    productConfig: ProductConfig,
    filters: FilterState
): {
    data: { [key: string]: SummaryTableNode };
    grandTotal: GrandTotal;
    uniqueParentGroups: string[];
    uniqueChildGroups: string[];
    uniqueManufacturers: string[];
    uniqueCreators: string[];
    uniqueProducts: string[];
} {
    const summaryTableData: { [key: string]: SummaryTableNode } = {};

    // Sets to collect unique values for dropdowns
    const parentGroupsForFilter = new Set<string>();
    const childGroupsForFilter = new Set<string>();
    const manufacturersForFilter = new Set<string>();
    const creatorsForFilter = new Set<string>();
    const productsForFilter = new Set<string>();

    // Mapping key codes to data extraction logic
    const valueExtractors: { [key: string]: (row: DataRow) => string } = {
        'parent': (row) => productConfig.childToParentMap[getRowValue(row, COL.MA_NHOM_HANG)] || 'Không xác định',
        'child': (row) => productConfig.childToSubgroupMap[getRowValue(row, COL.MA_NHOM_HANG)] || 'Không xác định',
        'manufacturer': (row) => getRowValue(row, COL.MANUFACTURER) || 'Không rõ',
        'creator': (row) => abbreviateName(getRowValue(row, COL.NGUOI_TAO) || 'Không xác định'),
        'product': (row) => getRowValue(row, COL.PRODUCT) || 'Sản phẩm lỗi tên'
    };

    const drilldownOrder = (filters.summaryTable.drilldownOrder && filters.summaryTable.drilldownOrder.length > 0)
        ? filters.summaryTable.drilldownOrder
        : ['parent', 'child', 'manufacturer', 'creator', 'product'];

    filteredValidSalesData.forEach(row => {
        const parentVal = valueExtractors['parent'](row);
        const childVal = valueExtractors['child'](row);
        const manufacturerVal = valueExtractors['manufacturer'](row);
        const creatorVal = valueExtractors['creator'](row);
        const productVal = valueExtractors['product'](row);

        parentGroupsForFilter.add(parentVal);
        childGroupsForFilter.add(childVal);
        manufacturersForFilter.add(manufacturerVal);
        creatorsForFilter.add(creatorVal);
        productsForFilter.add(productVal);

        if (filters.summaryTable.parent.length > 0 && !filters.summaryTable.parent.includes(parentVal)) return;
        if (filters.summaryTable.child.length > 0 && !filters.summaryTable.child.includes(childVal)) return;
        if (filters.summaryTable.manufacturer && filters.summaryTable.manufacturer.length > 0 && !filters.summaryTable.manufacturer.includes(manufacturerVal)) return;
        if (filters.summaryTable.creator && filters.summaryTable.creator.length > 0 && !filters.summaryTable.creator.includes(creatorVal)) return;
        if (filters.summaryTable.product && filters.summaryTable.product.length > 0 && !filters.summaryTable.product.includes(productVal)) return;

        const quantity = Number(getRowValue(row, COL.QUANTITY)) || 0;
        const price = Number(getRowValue(row, COL.PRICE)) || 0;
        const revenue = price; 
        const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
        const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
        const productName = getRowValue(row, COL.PRODUCT);

        const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
        const revenueQD = revenue * heso;

        // Logic trọng số số lượng Vieon
        const isVieon = childVal === 'Vieon' || parentVal === 'Vieon' || (productName || '').toString().includes('VieON');
        const weightedQuantity = isVieon ? (quantity * heso) : quantity;

        const keys: string[] = [];
        for (const levelKey of drilldownOrder) {
            if (valueExtractors[levelKey]) {
                keys.push(valueExtractors[levelKey](row));
            }
        }

        let currentNode: { [key: string]: SummaryTableNode } | undefined = summaryTableData;
        keys.forEach(key => {
            if (!currentNode) return;
            if (!currentNode[key]) {
                currentNode[key] = { 
                    totalQuantity: 0, 
                    totalRevenue: 0, 
                    totalTraGop: 0, 
                    totalRevenueQD: 0, 
                    children: {} 
                };
            }
            currentNode[key].totalQuantity += weightedQuantity;
            currentNode[key].totalRevenue += revenue;
            currentNode[key].totalRevenueQD += revenueQD;
            if (getHinhThucThanhToan(row) === 'tra_gop') {
                currentNode[key].totalTraGop += revenue;
            }
            currentNode = currentNode[key].children;
        });
    });

    const grandTotal: GrandTotal = Object.values(summaryTableData).reduce((acc, node) => {
        acc.totalQuantity += node.totalQuantity;
        acc.totalRevenue += node.totalRevenue;
        acc.totalRevenueQD += node.totalRevenueQD;
        acc.totalTraGop += node.totalTraGop;
        return acc;
    }, { totalQuantity: 0, totalRevenue: 0, totalRevenueQD: 0, totalTraGop: 0, aov: 0, traGopPercent: 0 });

    grandTotal.aov = grandTotal.totalQuantity > 0 ? grandTotal.totalRevenue / grandTotal.totalQuantity : 0;
    grandTotal.traGopPercent = grandTotal.totalRevenue > 0 ? (grandTotal.totalTraGop / grandTotal.totalRevenue) * 100 : 0;

    const sortedSummaryTableData = sortSummaryData(summaryTableData, filters.summaryTable.sort.column, filters.summaryTable.sort.direction);

    return {
        data: sortedSummaryTableData,
        grandTotal,
        uniqueParentGroups: [...parentGroupsForFilter].sort(),
        uniqueChildGroups: [...childGroupsForFilter].sort(),
        uniqueManufacturers: [...manufacturersForFilter].sort(),
        uniqueCreators: [...creatorsForFilter].sort(),
        uniqueProducts: [...productsForFilter].sort()
    };
}


export function calculateWarehouseSummary(
    allData: DataRow[],
    filters: FilterState,
    productConfig: ProductConfig
): WarehouseSummaryRow[] | null {
    const mainStartDate = filters.startDate ? new Date(filters.startDate) : null;
    if (mainStartDate) mainStartDate.setHours(0, 0, 0, 0);
    const mainEndDate = filters.endDate ? new Date(filters.endDate) : null;
    if (mainEndDate) mainEndDate.setHours(23, 59, 59, 999);

    const dataForWarehouseSummary = allData.filter(row => {
        const rowDate = row.parsedDate;
        if (!((!mainStartDate || rowDate >= mainStartDate) && (!mainEndDate || rowDate <= mainEndDate))) return false;
        if (filters.xuat !== 'all') {
            const xuatValue = getRowValue(row, COL.XUAT) || '';
            const xuatStatus = xuatValue.toLowerCase().includes('đã') ? 'Đã' : 'Chưa';
            if (xuatStatus !== filters.xuat) return false;
        }
        if (filters.trangThai.length > 0 && !filters.trangThai.includes(getRowValue(row, COL.TRANG_THAI))) return false;
        return true;
    });

    const uniqueKhos = [...new Set(allData.map(r => getRowValue(r, COL.KHO)).filter(Boolean))];
    if (uniqueKhos.length <= 1) return null;

    const summaryByKho: { [key: string]: any } = {};
    uniqueKhos.forEach(kho => {
        summaryByKho[kho] = {
            customers: new Set<string>(),
            doanhThuTraCham: 0,
            slThuHo: 0,
            metrics: {
                byIndustry: {},
                byGroup: {},
                byManufacturer: {},
                byIndustryAndManufacturer: {},
                byGroupAndManufacturer: {},
            },
        };
    });

    const initMetricValues = (): MetricValues => ({ quantity: 0, revenue: 0, revenueQD: 0 });

    dataForWarehouseSummary.forEach(row => {
        const khoName = getRowValue(row, COL.KHO);
        if (!khoName || !summaryByKho[khoName]) return;

        const summary = summaryByKho[khoName];

        if (HINH_THUC_XUAT_THU_HO.has(getRowValue(row, COL.HINH_THUC_XUAT))) {
            summary.slThuHo++;
        }

        if (!HINH_THUC_XUAT_THU_HO.has(getRowValue(row, COL.HINH_THUC_XUAT))) {
            const price = Number(getRowValue(row, COL.PRICE)) || 0;
            const quantity = Number(getRowValue(row, COL.QUANTITY)) || 0;
            const maNganhHang = getRowValue(row, COL.MA_NGANH_HANG);
            const maNhomHang = getRowValue(row, COL.MA_NHOM_HANG);
            const productName = getRowValue(row, COL.PRODUCT);
            const customer = getRowValue(row, COL.CUSTOMER_NAME);

            const heso = getHeSoQuyDoi(maNganhHang, maNhomHang, productConfig, productName);
            const rowRevenue = price; 
            const rowRevenueQD = rowRevenue * heso;

            // Trọng số Vieon
            const industry = productConfig.childToParentMap[maNhomHang] || 'Khác';
            const group = productConfig.childToSubgroupMap[maNhomHang] || 'Khác';
            const isVieon = group === 'Vieon' || industry === 'Vieon' || (productName || '').toString().includes('VieON');
            const weightedQuantity = isVieon ? (quantity * heso) : quantity;

            if (customer) summary.customers.add(customer);
            if (HINH_THUC_XUAT_TRA_GOP.has(getRowValue(row, COL.HINH_THUC_XUAT))) {
                summary.doanhThuTraCham += rowRevenue;
            }

            const manufacturer = getRowValue(row, COL.MANUFACTURER) || 'Không rõ';

            // Aggregate by industry
            if (!summary.metrics.byIndustry[industry]) summary.metrics.byIndustry[industry] = initMetricValues();
            summary.metrics.byIndustry[industry].quantity += weightedQuantity;
            summary.metrics.byIndustry[industry].revenue += rowRevenue;
            summary.metrics.byIndustry[industry].revenueQD += rowRevenueQD;

            // Aggregate by group
            if (!summary.metrics.byGroup[group]) summary.metrics.byGroup[group] = initMetricValues();
            summary.metrics.byGroup[group].quantity += weightedQuantity;
            summary.metrics.byGroup[group].revenue += rowRevenue;
            summary.metrics.byGroup[group].revenueQD += rowRevenueQD;

            // Aggregate by manufacturer
            if (!summary.metrics.byManufacturer[manufacturer]) summary.metrics.byManufacturer[manufacturer] = initMetricValues();
            summary.metrics.byManufacturer[manufacturer].quantity += weightedQuantity;
            summary.metrics.byManufacturer[manufacturer].revenue += rowRevenue;
            summary.metrics.byManufacturer[manufacturer].revenueQD += rowRevenueQD;

            // Aggregate by industry and manufacturer
            if (!summary.metrics.byIndustryAndManufacturer[industry]) summary.metrics.byIndustryAndManufacturer[industry] = {};
            if (!summary.metrics.byIndustryAndManufacturer[industry][manufacturer]) summary.metrics.byIndustryAndManufacturer[industry][manufacturer] = initMetricValues();
            summary.metrics.byIndustryAndManufacturer[industry][manufacturer].quantity += weightedQuantity;
            summary.metrics.byIndustryAndManufacturer[industry][manufacturer].revenue += rowRevenue;
            summary.metrics.byIndustryAndManufacturer[industry][manufacturer].revenueQD += rowRevenueQD;

            // Aggregate by group and manufacturer
            if (!summary.metrics.byGroupAndManufacturer[group]) summary.metrics.byGroupAndManufacturer[group] = {};
            if (!summary.metrics.byGroupAndManufacturer[group][manufacturer]) summary.metrics.byGroupAndManufacturer[group][manufacturer] = initMetricValues();
            summary.metrics.byGroupAndManufacturer[group][manufacturer].quantity += weightedQuantity;
            summary.metrics.byGroupAndManufacturer[group][manufacturer].revenue += rowRevenue;
            summary.metrics.byGroupAndManufacturer[group][manufacturer].revenueQD += rowRevenueQD;
        }
    });

    return uniqueKhos
        .filter(kho => summaryByKho[kho])
        .map(khoName => {
            const summary = summaryByKho[khoName];

            const totalMetrics = Object.values(summary.metrics.byIndustry as Record<string, MetricValues>)
                .reduce((acc, metric) => {
                    acc.revenue += metric.revenue;
                    acc.revenueQD += metric.revenueQD;
                    return acc;
                }, { revenue: 0, revenueQD: 0 });

            const doanhThuThuc = totalMetrics.revenue;
            const doanhThuQD = totalMetrics.revenueQD;
            const hieuQuaQD = doanhThuThuc > 0 ? ((doanhThuQD - doanhThuThuc) / doanhThuThuc) * 100 : 0;
            const traChamPercent = doanhThuThuc > 0 ? (summary.doanhThuTraCham / doanhThuThuc) * 100 : 0;

            return {
                khoName,
                doanhThuThuc,
                doanhThuQD,
                hieuQuaQD,
                slTiepCan: summary.customers.size,
                slThuHo: summary.slThuHo,
                traChamPercent: traChamPercent,
                doanhThuTraCham: summary.doanhThuTraCham,
                metrics: summary.metrics,
            };
        })
        .sort((a,b) => b.doanhThuQD - a.doanhThuQD);
}

