import { calculateRowQD } from '../utils/calculationUtils';
import type { DataRow, KpiData } from '../types';

export function processRawData(rows: DataRow[]): { filtered: DataRow[], kpis: KpiData } {
  let totalThuc = 0;
  let totalQD = 0;
  let countThuHo = 0;
  // Initialize missing KPI fields
  let traGopValue = 0;
  let traGopCount = 0;
  let dtThucChoXuat = 0;
  let dtQDChoXuat = 0;

  const processed = rows.map(row => {
    // Tích hợp tính toán quy đổi vào từng dòng
    const { revenue, revenueQD, factor } = calculateRowQD(row);

    // Logic: Identify special order types
    // Using string includes as a simple check against available raw data
    const xuatRaw = (row['Trạng thái xuất'] || '').toString().toLowerCase();
    const isUnshipped = xuatRaw.includes('chưa');

    const hinhThucXuatRaw = (row['Hình thức xuất'] || '').toString().toLowerCase();
    const isThuHo = hinhThucXuatRaw.includes('thu hộ');
    const isTraGop = hinhThucXuatRaw.includes('trả góp');

    // Tích lũy tổng - Only for non-Thu Ho orders
    if (!isThuHo) {
      totalThuc += revenue;
      totalQD += revenueQD;

      if (isTraGop) {
        traGopValue += revenue;
        traGopCount++;
      }

      if (isUnshipped) {
        dtThucChoXuat += revenue;
        dtQDChoXuat += revenueQD;
      }
    } else {
      countThuHo++;
    }

    return {
      ...row,
      computedRevenue: revenue,
      computedRevenueQD: revenueQD,
      appliedFactor: factor
    };
  });

  // FIX: Populate missing fields required by KpiData interface
  const kpis: KpiData = {
    totalRevenue: totalThuc,
    doanhThuQD: totalQD,
    hieuQuaQD: totalThuc > 0 ? (totalQD - totalThuc) / totalThuc : 0,
    soLuongThuHo: countThuHo,
    traGopPercent: totalThuc > 0 ? (traGopValue / totalThuc) * 100 : 0,
    traGopValue: traGopValue,
    traGopCount: traGopCount,
    doanhThuThucChoXuat: dtThucChoXuat,
    doanhThuQDChoXuat: dtQDChoXuat,
  };

  return { filtered: processed, kpis };
}

import { get } from 'svelte/store';
import { productConfig } from '../stores/dashboardStore';

/**
 * Lấy hệ số quy đổi dựa trên quy tắc ưu tiên
 * 1. Tên sản phẩm Vieon (Ưu tiên tuyệt đối)
 * 2. Cấu hình Admin từ file Google Sheets
 * 3. Fallback theo tên ngành hàng
 */
export function getConversionFactor(row: any): number {
  const productName = (row['Tên sản phẩm'] || row['Tên Sản Phẩm'] || '').toString();
  const maNhomHang = (row['Nhóm hàng'] || '').toString().trim();
  const nganhHangText = (row['Ngành hàng'] || '').toString().toLowerCase();

  // 1. Logic đặc thù cho sản phẩm Vieon (Dựa trên tên)
  if (productName.includes('VieON VIP')) {
    if (productName.includes('01 tháng')) return 1;
    if (productName.includes('03 tháng')) return 2;
    if (productName.includes('06 tháng')) return 4;
    return 1; 
  }

  // 2. Kiểm tra trong map cấu hình tải từ Google Sheets
  const config = get(productConfig);
  if (config && config[maNhomHang]) {
    return config[maNhomHang];
  }

  // 3. Fallback logic dựa trên từ khóa ngành hàng (Mặc định hệ thống)
  if (nganhHangText.includes('phụ kiện')) return 3.37;
  if (nganhHangText.includes('gia dụng')) return 1.85;
  if (nganhHangText.includes('bảo hiểm')) return 4.18;
  if (nganhHangText.includes('sim')) return 5.45;
  if (nganhHangText.includes('đồng hồ') || nganhHangText.includes('wearable')) return 3.0;
  if (nganhHangText.includes('laptop') || nganhHangText.includes('tablet')) return 1.2;

  return 1.0; // Mặc định cho Điện thoại, Tivi, v.v.
}

/**
 * Tính toán các giá trị quy đổi cho một dòng đơn hàng
 */
export function calculateRowMetrics(row: any) {
  const price = parseFloat(row['Giá bán_1']) || 0;
  const factor = getConversionFactor(row);

  return {
    revenue: price,
    revenueQD: price * factor,
    factor: factor
  };
}

import type { DataRow, KpiData } from '../types';

/**
 * Tổng hợp toàn bộ chỉ số KPI từ danh sách đơn hàng đã lọc
 */
export function summarizeKpis(rows: DataRow[], unshippedRows: DataRow[]): KpiData {
  let totalRevenue = 0;
  let doanhThuQD = 0;
  let traGopValue = 0;
  let traGopCount = 0;
  let soLuongThuHo = 0;

  rows.forEach(row => {
    const hinhThucXuat = (row['Hình thức xuất'] || '').toString().toLowerCase();

    // Nếu là Thu hộ, chỉ đếm số lượng, không tính doanh thu
    if (hinhThucXuat.includes('thu hộ')) {
      soLuongThuHo++;
      return;
    }

    const rev = row.computedRevenue || 0;
    const revQD = row.computedRevenueQD || 0;

    totalRevenue += rev;
    doanhThuQD += revQD;

    if (hinhThucXuat.includes('trả góp')) {
      traGopValue += rev;
      traGopCount++;
    }
  });

  // Tính toán doanh thu chờ xuất (từ danh sách chưa xuất)
  const dtThucChoXuat = unshippedRows.reduce((sum, r) => sum + (r.computedRevenue || 0), 0);
  const dtQDChoXuat = unshippedRows.reduce((sum, r) => sum + (r.computedRevenueQD || 0), 0);

  return {
    totalRevenue,
    doanhThuQD,
    hieuQuaQD: totalRevenue > 0 ? (doanhThuQD - totalRevenue) / totalRevenue : 0,
    soLuongThuHo,
    traGopPercent: totalRevenue > 0 ? (traGopValue / totalRevenue) * 100 : 0,
    traGopValue,
    traGopCount,
    doanhThuThucChoXuat: dtThucChoXuat,
    doanhThuQDChoXuat: dtQDChoXuat
  };
}

import { calculateRowMetrics } from '../utils/calculationUtils';
import { summarizeKpis } from './kpiService';
import type { DataRow, ProcessedData, TrendData, IndustryData, Employee } from '../types';

/**
 * Hàm chính thực hiện "xay" dữ liệu thô thành kết quả hiển thị trên Dashboard
 */
export function processDashboardData(rows: DataRow[]): ProcessedData {
  const dailyTrends: Record<string, { revenue: number, revenueQD: number, date: Date }> = {};
  const shifts: Record<string, { revenue: number, revenueQD: number }> = {
    "Ca 1 (8h-11h)": { revenue: 0, revenueQD: 0 },
    "Ca 2 (11h-14h)": { revenue: 0, revenueQD: 0 },
    "Ca 3 (14h-17h)": { revenue: 0, revenueQD: 0 },
    "Ca 4 (17h-20h)": { revenue: 0, revenueQD: 0 },
    "Ca 5 (Sau 20h)": { revenue: 0, revenueQD: 0 }
  };
  const industries: Record<string, IndustryData> = {};
  const unshipped: DataRow[] = [];

  // Gắn thêm các trường tính toán cho từng dòng
  const enrichedRows = rows.map(row => {
    const metrics = calculateRowMetrics(row);
    const enriched = { 
      ...row, 
      computedRevenue: metrics.revenue, 
      computedRevenueQD: metrics.revenueQD 
    };

    // 1. Phân loại chờ xuất
    const xuatStatus = (row['Trạng thái xuất'] || '').toString().toLowerCase();
    if (xuatStatus.includes('chưa')) {
      unshipped.push(enriched);
    }

    // 2. Xử lý Xu hướng (Trends)
    if (row.parsedDate) {
      const dateKey = row.parsedDate.toISOString().split('T')[0];
      if (!dailyTrends[dateKey]) {
        dailyTrends[dateKey] = { revenue: 0, revenueQD: 0, date: row.parsedDate };
      }
      dailyTrends[dateKey].revenue += metrics.revenue;
      dailyTrends[dateKey].revenueQD += metrics.revenueQD;

      // Phân bổ ca
      const hour = row.parsedDate.getHours();
      let shiftKey = "Ca 5 (Sau 20h)";
      if (hour < 11) shiftKey = "Ca 1 (8h-11h)";
      else if (hour < 14) shiftKey = "Ca 2 (11h-14h)";
      else if (hour < 17) shiftKey = "Ca 3 (14h-17h)";
      else if (hour < 20) shiftKey = "Ca 4 (17h-20h)";

      shifts[shiftKey].revenue += metrics.revenue;
      shifts[shiftKey].revenueQD += metrics.revenueQD;
    }

    // 3. Xử lý Ngành hàng
    const nganhHang = row['Ngành hàng'] || 'Khác';
    if (!industries[nganhHang]) {
      industries[nganhHang] = { name: nganhHang, revenue: 0, quantity: 0 };
    }
    industries[nganhHang].revenue += metrics.revenue;
    industries[nganhHang].quantity += (parseFloat(row['Số lượng']) || 1);

    return enriched;
  });

  return {
    kpis: summarizeKpis(enrichedRows, unshipped),
    trendData: { daily: dailyTrends, shifts },
    industryData: Object.values(industries).sort((a, b) => b.revenue - a.revenue),
    employeeData: {
      fullSellerArray: [], // Sẽ được xử lý chi tiết ở bước Employee Service
      averages: {}
    },
    unshippedOrders: unshipped,
    lastUpdated: new Date().toLocaleString('vi-VN'),
    reportSubTitle: "Dữ liệu được xử lý tự động theo hệ số quy đổi mới nhất."
  };
}

import type { DataRow, FilterState } from '../types';

/**
 * Hàm lọc dữ liệu thô dựa trên trạng thái bộ lọc hiện tại
 */
export function applyAllFilters(allData: DataRow[], filters: FilterState): DataRow[] {
  if (!allData || allData.length === 0) return [];

  return allData.filter(row => {
    // 1. Lọc theo Kho (Single Select)
    if (filters.kho !== 'all' && row['normalizedKho'] !== filters.kho) return false;

    // 2. Lọc theo Trạng thái xuất (Single Select)
    if (filters.xuat !== 'all') {
      if (row['normalizedXuat'] !== filters.xuat) return false;
    }

    // 3. Lọc theo Khoảng ngày (Date Range)
    if (filters.startDate || filters.endDate) {
      const rowDate = row.parsedDate;
      if (!rowDate) return false;

      if (filters.startDate) {
        const start = new Date(filters.startDate);
        start.setHours(0, 0, 0, 0);
        if (rowDate < start) return false;
      }

      if (filters.endDate) {
        const end = new Date(filters.endDate);
        end.setHours(23, 59, 59, 999);
        if (rowDate > end) return false;
      }
    }

    // 4. Lọc theo Người tạo (Multi-select)
    if (filters.nguoiTao.length > 0 && !filters.nguoiTao.includes(row['normalizedNguoiTao'])) return false;

    // 5. Lọc theo Trạng thái hồ sơ (Multi-select)
    if (filters.trangThai.length > 0 && !filters.trangThai.includes(row['normalizedTrangThai'])) return false;

    return true;
  });
}

import type { DataRow, Employee, ProductConfig } from '../types';
import { getConversionFactor } from '../utils/calculationUtils';

/**
 * Tổng hợp dữ liệu từ danh sách đơn hàng thành mảng nhân viên
 */
export function summarizeEmployees(rows: DataRow[], deptMap: Record<string, string>): Employee[] {
  const empMap: Record<string, any> = {};

  rows.forEach(row => {
    const name = row.normalizedNguoiTao || 'Không tên';
    const rev = row.computedRevenue || 0;
    const revQD = row.computedRevenueQD || 0;
    const hinhThucXuat = (row['Hình thức xuất'] || '').toString().toLowerCase();
    const industry = (row['Ngành hàng'] || '').toString().toLowerCase();

    if (!empMap[name]) {
      // Lấy ID từ tên (VD: "12345 - Nguyễn Văn A")
      const id = name.split(' - ')[0];
      empMap[name] = {
        name,
        department: deptMap[id] || 'Chưa phân ca',
        doanhThuThuc: 0,
        doanhThuQD: 0,
        slTraGop: 0,
        totalOrders: 0,
        slTiepCan: new Set(), // Dùng Set để đếm số khách hàng duy nhất
      };
    }

    const emp = empMap[name];

    // Chỉ tính doanh thu nếu không phải thu hộ
    if (!hinhThucXuat.includes('thu hộ')) {
      emp.doanhThuThuc += rev;
      emp.doanhThuQD += revQD;
      emp.totalOrders += 1;
      if (hinhThucXuat.includes('trả góp')) emp.slTraGop += 1;
    }

    // Đếm số khách tiếp cận (dựa trên tên khách hàng hoặc mã đơn)
    const customer = row['Tên khách hàng'] || row['Mã đơn hàng'];
    if (customer) emp.slTiepCan.add(customer);
  });

  return Object.values(empMap).map(emp => ({
    ...emp,
    slTiepCan: emp.slTiepCan.size,
    hieuQuaValue: emp.doanhThuThuc > 0 ? ((emp.doanhThuQD - emp.doanhThuThuc) / emp.doanhThuThuc) * 100 : 0,
    traChamPercent: emp.totalOrders > 0 ? (emp.slTraGop / emp.totalOrders) * 100 : 0
  })).sort((a, b) => b.doanhThuQD - a.doanhThuQD);
}

