import React, { useState, useEffect } from 'react';
import { Icon } from './Icon';

const ThemeToggle: React.FC = () => {
    const [isDark, setIsDark] = useState(false);

    useEffect(() => {
        const theme = localStorage.getItem('theme');
        const darkMode = theme === 'dark' || (!theme && window.matchMedia('(prefers-color-scheme: dark)').matches);
        setIsDark(darkMode);
        if (darkMode) document.documentElement.classList.add('dark');
    }, []);

    const toggle = () => {
        const next = !isDark;
        setIsDark(next);
        if (next) {
            document.documentElement.classList.add('dark');
            localStorage.setItem('theme', 'dark');
        } else {
            document.documentElement.classList.remove('dark');
            localStorage.setItem('theme', 'light');
        }
    };

    return (
        <button 
            onClick={toggle}
            className="p-2.5 rounded-xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-sm hover:scale-110 transition-all text-amber-500 dark:text-indigo-400"
            title="Chuyển đổi giao diện"
        >
            <Icon name={isDark ? 'moon' : 'sun'} size={5} />
        </button>
    );
};

export default ThemeToggle;

import React, { useState, useEffect } from 'react';
import { Icon } from '../common/Icon';

const CouponView: React.FC = () => {
    const [amount, setAmount] = useState<number>(0);
    const [result, setResult] = useState<{val: number, count: number}[]>([]);
    const denoms = [500000, 200000, 100000, 50000, 20000, 10000];

    useEffect(() => {
        let rem = amount;
        const res = denoms.map(d => {
            const count = Math.floor(rem / d);
            rem %= d;
            return { val: d, count };
        }).filter(item => item.count > 0);
        setResult(res);
    }, [amount]);

    return (
        <div className="animate-fade-in p-8">
            <h2 className="text-3xl font-black text-slate-800 dark:text-white uppercase mb-8">Đổi Coupon Thưởng</h2>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="chart-card p-8">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest block mb-4">Tổng số tiền cần quy đổi</label>
                    <input 
                        type="number" 
                        value={amount} 
                        onChange={(e) => setAmount(Number(e.target.value))}
                        className="w-full text-5xl font-black text-indigo-600 bg-transparent border-none focus:ring-0 mb-6"
                        placeholder="0"
                    />
                    <div className="grid grid-cols-3 gap-2">
                        {[100000, 500000, 1000000, 5000000].map(v => (
                            <button key={v} onClick={() => setAmount(amount + v)} className="p-3 text-xs font-bold bg-slate-100 dark:bg-slate-700 rounded-xl hover:bg-indigo-50 transition-colors">+{v.toLocaleString()}đ</button>
                        ))}
                        <button onClick={() => setAmount(0)} className="p-3 text-xs font-bold text-red-500 bg-red-50 rounded-xl">Xóa</button>
                    </div>
                </div>

                <div className="space-y-4">
                    {result.length > 0 ? result.map((item, i) => (
                        <div key={i} className="chart-card p-5 flex justify-between items-center border-l-8 border-indigo-500">
                            <div className="flex items-center gap-4">
                                <div className="p-3 bg-indigo-50 dark:bg-slate-700 rounded-lg"><Icon name="banknote" size={5} className="text-indigo-600" /></div>
                                <div>
                                    <p className="text-xs text-slate-400 font-bold uppercase">Mệnh giá</p>
                                    <h4 className="text-xl font-black">{item.val.toLocaleString()}đ</h4>
                                </div>
                            </div>
                            <div className="text-right">
                                <p className="text-xs text-slate-400 font-bold uppercase">Số tờ</p>
                                <h4 className="text-3xl font-black text-indigo-600">x{item.count}</h4>
                            </div>
                        </div>
                    )) : (
                        <div className="h-64 border-4 border-dashed border-slate-100 dark:border-slate-800 rounded-[2rem] flex flex-col items-center justify-center text-slate-300">
                            <Icon name="ticket" size={10} />
                            <p className="font-bold mt-4">Nhập số tiền để bắt đầu quy đổi</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

