        drilldownOrder: ['parent', 'child', 'manufacturer', 'creator', 'product'],
        sort: { column: 'totalRevenue', direction: 'desc' }
    }
};

export const filterState = writable<FilterState>(initialFilterState);

export const uniqueFilters = derived([originalData, departmentMap], ([$data, $deptMap]) => {
    if (!$data || $data.length === 0) return { kho: [], trangThai: [], nguoiTao: [], department: [] };
    const khoSet = new Set<string>();
    const statusSet = new Set<string>();
    const creatorSet = new Set<string>();
    $data.forEach(row => {
        if (row['normalizedKho']) khoSet.add(String(row['normalizedKho']));
        if (row['normalizedTrangThai']) statusSet.add(String(row['normalizedTrangThai']));
        if (row['normalizedNguoiTao']) creatorSet.add(String(row['normalizedNguoiTao']));
    });
    return {
        kho: Array.from(khoSet).sort(),
        trangThai: Array.from(statusSet).sort(),
        nguoiTao: Array.from(creatorSet).sort(),
        department: Array.from(new Set(Object.values($deptMap))).sort() as string[]
    };
});

