            const link = document.createElement('a');
            const fileName = name ? `ket-qua-thue-tncn-${name.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-')}.png` : 'ket-qua-thue-tncn.png';
            link.download = fileName;
