                                      <ResultRow label="   - Bảo hiểm, phí công đoàn" value={formatCurrency(results.insuranceDeductions + results.unionFeeDeduction)} isSubtle />
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8">
